@use '../../styles/tokens' as *;

$file-picker-pill-height: 26px;
$file-picker-pill-max-width: 240px;
$file-picker-remove-size: 14px;

.form-file-picker {
  display: flex;
  flex-direction: column;
  gap: $space-2;
}

.form-file-picker__native-input {
  position: absolute;
  width: 0;
  height: 0;
  opacity: 0;
  pointer-events: none;
}

.form-file-picker__files {
  display: flex;
  flex-wrap: wrap;
  gap: $space-1;
}

.form-file-picker__pill {
  display: inline-flex;
  align-items: center;
  gap: $space-1;
  height: $file-picker-pill-height;
  padding: 0 $space-1 0 $space-2;
  background: rgba($color-accent, 0.15);
  color: $color-accent;
  border-radius: $radius-kbd;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  line-height: 1;
  max-width: $file-picker-pill-max-width;
}

.form-file-picker__pill-icon {
  flex-shrink: 0;
}

.form-file-picker__pill-name {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  flex: 1;
  min-width: 0;
}

.form-file-picker__pill-size {
  flex-shrink: 0;
  font-size: $font-xs;
  opacity: 0.7;
}

.form-file-picker__pill-remove {
  display: flex;
  align-items: center;
  justify-content: center;
  width: $file-picker-remove-size;
  height: $file-picker-remove-size;
  padding: 0;
  border: none;
  border-radius: $radius-sm;
  background: transparent;
  color: $color-accent;
  cursor: pointer;
  opacity: 0.6;
  flex-shrink: 0;
  transition: opacity $transition-fast ease;

  &:hover {
    opacity: 1;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: 2px;
  }
}

.form-file-picker__browse {
  display: inline-flex;
  align-items: center;
  gap: $space-1;
  align-self: flex-start;
  height: $space-8;
  padding: 0 $space-3;
  border: 1px solid $border-100;
  border-radius: $radius-md;
  background: $color-background;
  color: $text-600;
  font-family: $font-family;
  font-size: $font-sm;
  font-weight: $font-weight-medium;
  cursor: pointer;
  transition:
    border-color $transition-fast ease,
    color $transition-fast ease,
    background-color $transition-fast ease;

  &:hover {
    border-color: $border-200;
    color: $color-text-primary;
    background: $color-surface-hover;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: 2px;
  }

  .form-field--error & {
    border-color: $color-destructive;
  }
}

